const raw=fs.readFileSync(M+'/facts-509424983.md','utf8');
const lines=raw.split(/\r?\n/).filter(l=>l.trim().startsWith('- ['));
const list=topics.topics||topics;
const counts={}; const misc=[];
for(const l of lines){
  const low=l.toLowerCase();
  let hit=null;
  for(const t of list){ if((t.keywords||[]).some(k=>low.includes(k.toLowerCase()))){hit=t.name;break;} }
